queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasLocations ?child ; p:hasProductions ?parent . } GROUP BY ?child }
  ?child p:Type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Productions } }
  FILTER(?nf = ?total)
}

